var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"치후유, 다 입었으면 이제 나와볼래요?","JPN":"千冬、着替え終わったら出てきてください。","ENG":"Chifuyu, if you're finished dressing, come out now.","TWN":"千冬，穿好了就出來吧？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"......저어, 당주님? 이건 전투복이 아니라 그냥 평범한 수영복 같습니다만.","JPN":"……あの、当主？　これは戦闘服ではなく、水着のようですが？","ENG":"Erm, Leader? I'm afraid this is not a combat uniform, but an ordinary-looking swimsuit.","TWN":"……呃，家主大人？這個好像不是戰鬥服，只是普通的泳裝。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"헤헤, 잘 어울리는구나.","JPN":"ふふ、よく似合ってるわ。","ENG":"Heh heh, you look good.","TWN":"嘿嘿，很好看喔。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"사실 배에서 이상한 기운이 느껴진다는 건 거짓말이었어. 속여서 미안해.","JPN":"実は船から不吉な気を感じるという話は嘘よ。騙してごめんなさい。","ENG":"I'm sorry, but I didn't sense any strange energy from this ship. It was just a lie.","TWN":"其實我跟妳說船上有不祥氣息的話是騙妳的，對不起。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"네? 하지만 왜 굳이 그런 거짓말을 하신 겁니까?","JPN":"はい？　なぜそのような嘘を？","ENG":"Pardon? But why did you lie?","TWN":"什麼？可是，為什麼妳要說這種謊？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"가문의 어르신들께서 알게 되면 좋게 보시지 않을 겁니다.","JPN":"ここに来たことを七原家の皆さんに知られれば、良い気はしないかと思いますが。","ENG":"The elders of the Family wouldn't look favorably on you if they knew you lied.","TWN":"家族的長輩們知道了，會不高興的。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"그냥 바다를 보러 나오고 싶었어. 이렇게 우리 둘이서 함께 말이야.","JPN":"ただ海を見に来たかったの。あなたと二人で。","ENG":"I just wanted to come out and enjoy the sea, with you.","TWN":"我只是想和妳一起出來看海而已。像這樣，我們兩個一起。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"치후유, 그 동안 많이 힘들었지?","JPN":"千冬、今まで辛かったよね？","ENG":"Chifuyu, things have been rough for you, haven't they?","TWN":"千冬，妳這段時間一定很辛苦吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"엄격한 집안 사람들이 주는 부담과 당주를 호위해야 한다는 의무 때문에 제대로 쉴 겨를조차 없었잖아.","JPN":"厳格な家柄に生まれたがためにのしかかる負担と、当主を守るという義務のせいで息をつく暇さえなかったと思うの。","ENG":"You couldn't even take a breather because of the pressure from the stern elders of the Family and your responsibility as my escort.","TWN":"妳每天都要承受那些嚴格長輩帶來的壓力，還肩負著保護家主的責任，連好好休息空檔都沒有，不是嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"게다가 늘 가문의 영지에서만 지내왔으니 바다 같은 건 더더욱 볼 겨를도 없었고.","JPN":"それに、一族の領地からあまり出たこともなかったから、海なんかなおさら見ることもなかったはずだし。","ENG":"You couldn't leave the Family's domain, either, never mind coming out to see the sea.","TWN":"而且妳一直生活在家族領地內，根本沒機會出去看看大海。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"그래서 할 수 있다면, 짊어진 것들을 잠시나마 다 털어두고서 이렇게 같이 바다를 와보고 싶었어.","JPN":"だから、できることなら肩の荷を少し下ろして、こうやって海を見に来たかったの。","ENG":"That's why I wanted to take you out here, to get away from it all.","TWN":"所以，如果可以的話，我希望妳能暫時放下肩上的責任，哪怕是一下也好，看看大海放鬆心情。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"미안하구나. 내 멋대로 저지른 일탈인데, 너까지 멋대로 공범으로 만들어버려서.","JPN":"本当にごめんなさい。私の勝手で、あなたまで共犯にしてしまって……","ENG":"I'm sorry I pulled you into this stupid scheme of mine.","TWN":"對不起，明明是我自己任性的脫軌行為，害妳也變成共犯了。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"괜찮습니다.","JPN":"心配無用です。","ENG":"It's okay.","TWN":"沒關係。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"전 당주님을 호위하는 무사. 당주님이 어떤 선택을 하든 저는 그저 그림자처럼 따를 뿐입니다.","JPN":"当主をお守りするのが我が務め。当主がどんな選択をしようと、私はただ影の如く従うのみです。","ENG":"I'm your escort. Whatever you do, I'll always follow you like your shadow, Lady Nanahara.","TWN":"我是家主的貼身護衛，無論家主做什麼決定，我都會形影不離。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"에이, 치후유~ 고맙긴 하지만 표현이 너무 딱딱해~","JPN":"千冬ったら。嬉しいけど、少し口調が固くないかしら？","ENG":"Come on, Chifuyu, you don't have to be so formal with me all the time.","TWN":"哎唷，千冬～妳說話也太死板了～"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"크음......","JPN":"ゴ、ゴホン……！","ENG":"Khhm...","TWN":"咳咳……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"저도 바다는 한 번쯤 와보고 싶었어요.","JPN":"私も一度くらいは海に来てみたかったです。","ENG":"I've also wanted to come to the sea, at least once.","TWN":"其實我也一直很想看看大海。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"......언니랑 같이.","JPN":"……姉さんと一緒に。","ENG":"With you, Chinatsu.","TWN":"……和姐姐一起。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};